import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Subindo arquivos de Log (Logs)","description":"Como subir arquivos de Log para resolução de problemas.","frontmatter":{"title":"Subindo arquivos de Log (Logs)","description":"Como subir arquivos de Log para resolução de problemas.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/players/troubleshooting/uploading-logs.md","filePath":"translated/pt_br/players/troubleshooting/uploading-logs.md","lastUpdated":1770561656000}`);var a={name:`pt_br/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Subindo arquivos de Log (Logs) <a class="header-anchor" href="#h1" aria-label="Permalink to “Subindo arquivos de Log (Logs)”">​</a></h1><p>Quando houver Correção de Falhas, é frenquentemente necessário prover arquivos de log para ajudar a identificar a causa das mesmas.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Por que eu deveria subir Logs? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Por que eu deveria subir Logs?”">​</a></h2><p>Subir Logs, permite outros a ajudar na resolução dos seus erros muito mais rapidamente do que, simplesmente, colocá-los em Chats ou posts de Fóruns. Isso também permite que você compartilhe os seus Logs, sem ter que copiá-los e colá-los múltiplas vezes.</p><p>Alguns Sites de Armazenamento também fornecem destacamento de Sintaxe para os Logs, o que os tornam muito mais fáceis de serem lidos. Também, podem censurar informações sensíveis. Como, por exemplo, &#39;nome de usuário&#39; ou informações do sistema.</p><h2 id="crash-reports" tabindex="-1">Relatórios de Travamento <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Relatórios de Travamento”">​</a></h2><p>Relatórios de Travamento são automaticamente gerados quando o jogo trava. Eles contêm informações sobre o travamento e não os reais Logs do jogo. Eles estão localizados no repositório <code>crash-reports</code> dentro do diretório do jogo.</p><p>Para mais informações sobre Relatórios de Travamento, veja <a href="./crash-reports">Crash Reports</a>.</p><h2 id="locating-logs" tabindex="-1">Localizando os Logs <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Localizando os Logs”">​</a></h2><p>Esse guia cobre o Iniciador Oficial de Minecraft (Popularmente referido como &quot;Vanilla Launcher&quot;) - para outros iniciadores, você deve consultar suas respectivas documentações.</p><p>Os Logs estão localizados no repositório <code>Logs</code> dentro do Diretório do jogo. O mesmo pode ser encontrado nas seguintes localidades, dependendo do seu sistema operacional:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>O Log mais recente tem o nome de <code>latest.log</code> e os anteriores usam o padrão nominal <code>yyyy-mm-dd_number.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Subindo Logs para a Internet <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Subindo Logs para a Internet”">​</a></h2><p>Os Logs podem ser submetidos online a uma variedade de serviços, como, por exemplo:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};